sql:
SELECT fabric_name, width, price_per_meter 
FROM fabrics 
WHERE availability = 1;

external_knowledge:
- 'total earnings' refers to the sum of the total costs across all orders;
- 'average time taken to process an order' means the average processing time for fabrics, converted to hours;
- 'fabric type that is mostly favored by the customers' indicates the fabric with the highest total quantity ordered.

sql:
SELECT SUM(total_cost) AS total_order_cost
FROM orders
WHERE user_id = 1;

SELECT COUNT(order_id) AS total_orders
FROM orders
WHERE shipping_address LIKE '%Anytown, USA%';

SELECT fabric_category, COUNT(fabric_type_name) AS number_of_fabric_types
FROM fabric_types
GROUP BY fabric_category;

